def fib(n: int) -> int:
    # Dictionary to store calculated values (memo)
    memo = {0: 0, 1: 1}

    def helper(x: int) -> int:
        # If the value is already in our memo, return it
        if x in memo:
            return memo[x]

        # Otherwise, calculate it recursively
        memo[x] = helper(x - 1) + helper(x - 2)
        return memo[x]

    return helper(n)

